const introQuestLessons: QuestLesson[] = introTermSeeds.slice(0, 200).map((seed, index) => {
  const stage = index + 1;
  const isBoss = stage % 10 === 0;
  const chapter = introChapters[Math.floor(index / 10)] ?? introChapters[introChapters.length - 1];

  return lesson({
    id: `intro-${seed.slug}`,
    mode: "intro",
    stage,
    title: seed.title,
    enemy: `${isBoss ? chapter.boss : chapter.enemy}：${seed.title}`,
    reward: isBoss ? chapter.medal : `${seed.title}の言葉カード`,
    question: seed.prompt,
    choices: [seed.correct, ...seed.wrong],
    correctIndex: 0,
    immediateAnswer: `正解は「${seed.correct}」です。`,
    explanation: seed.explanation,
    appLink: seed.appLink ?? toolLinks.calculator,
    column: seed.column,
    sources: seed.sources
  });
});

